import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppContext } from '../App';
import { configuracaoEmpresa, colaboradores as mockColaboradores } from '../data/mockData';

type ViewMode = 'login' | 'register' | 'confirm' | 'forgot';

const Login: React.FC = () => {
  const navigate = useNavigate();
  const { setIsAuthenticated, setColaboradores, setEmpresa, setUser, setIsConfigured, setEmpresas, setEmpresaId } = useContext(AppContext);
  
  const [mode, setMode] = useState<ViewMode>('login');
  const [email, setEmail] = useState('admin@salya.com');
  const [password, setPassword] = useState('admin123');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [name, setName] = useState('');
  const [confirmCode, setConfirmCode] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [errorString, setErrorString] = useState('');

  const executeLogin = (userEmail: string, userName: string) => {
    setIsAuthenticated(true);
    setUser({ email: userEmail, name: userName });

    if (userEmail === 'admin@salya.com') {
      const empresaComId = { ...configuracaoEmpresa, id: 1 };
      setEmpresas([empresaComId]);
      setEmpresaId(1);
      setEmpresa(empresaComId);
      setColaboradores(mockColaboradores.map(c => ({ ...c, empresaId: 1 })));
      setIsConfigured(true);
      navigate('/processamento');
    } else {
      setEmpresas([]);
      setEmpresaId(null);
      setEmpresa(null);
      setColaboradores([]);
      setIsConfigured(false);
      navigate('/configuracoes');
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setErrorString('');
    if (email && password) {
      // Simulate real auth fetching
      executeLogin(email, 'Administrador');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setErrorString('');
    if (password !== confirmPassword) {
      setErrorString('As palavras-passe não coincidem.');
      return;
    }
    if (name && email && password) {
      setMode('confirm');
    }
  };

  const handleConfirm = (e: React.FormEvent) => {
    e.preventDefault();
    if (confirmCode) {
      // Redirecionar para login após criar conta
      alert('Conta criada com sucesso! Por favor, faça login com as suas credenciais.');
      setMode('login');
      setEmail('');
      setPassword('');
      setName('');
      setConfirmPassword('');
      setConfirmCode('');
    }
  };

  const handleForgotPassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      // Logic for forgot password
      setMode('login');
      alert('Email de repor palavra-passe enviado com sucesso!');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-background-light dark:bg-background-dark">
      <div className="relative flex h-auto w-full max-w-[1100px] flex-col md:flex-row bg-white dark:bg-slate-900 rounded-xl shadow-2xl overflow-hidden">
        {/* Left Side - Branding */}
        <div className="hidden md:flex md:w-1/2 relative bg-primary items-center justify-center p-12 overflow-hidden">
          <div className="absolute inset-0 opacity-20 bg-cover bg-center" style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?w=800")' }}></div>
          <div className="absolute inset-0 bg-gradient-to-br from-primary via-primary/80 to-slate-900/40"></div>
          
          <div className="relative z-10 flex flex-col gap-6 text-white">
            <div className="flex items-center gap-3">
              <img src="/logo.png" alt="SALYA Logo" className="w-16 h-16 object-contain bg-white/10 p-2 rounded-lg" />
              <h1 className="text-3xl font-black tracking-tight">SALYA</h1>
            </div>
            
            <div className="space-y-4">
              <h2 className="text-4xl font-bold leading-tight">Emissão Rápida e Prática de Recibos de Salário</h2>
              <p className="text-white/80 text-lg">Cadastre a sua empresa, os seus funcionários, e emita recibos de salário na hora com todos os cálculos de descontos para o mercado angolano.</p>
            </div>
          </div>
          
          <div className="absolute bottom-8 left-12 flex items-center gap-2 text-white/60 text-xs">
            <span>Luanda, Angola</span>
            <span className="size-1 bg-white/40 rounded-full"></span>
            <span>Conformidade V3.2</span>
          </div>
        </div>

        {/* Right Side - Forms */}
        <div className="w-full md:w-1/2 p-8 md:p-16 flex flex-col justify-center">
          <div className="md:hidden flex items-center gap-3 mb-10">
            <img src="/logo.png" alt="SALYA Logo" className="w-10 h-10 object-contain" />
            <h1 className="text-2xl font-black tracking-tight text-slate-900 dark:text-white">SALYA</h1>
          </div>
          
          {mode === 'login' && (
            <>
              <div className="mb-8">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2">Bem-vindo de volta</h2>
                <p className="text-slate-500 dark:text-slate-400">Introduza as suas credenciais para aceder ao painel</p>
              </div>
              
              <form className="space-y-5" onSubmit={handleLogin}>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 dark:text-slate-300">Endereço de E-mail</label>
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 group-focus-within:text-primary transition-colors">
                      <span className="material-symbols-outlined text-xl">mail</span>
                    </div>
                    <input
                      type="email"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      className="w-full pl-10 pr-4 py-3.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all dark:text-white"
                      placeholder="seunome@empresa.ao"
                      required
                    />
                  </div>
                </div>
                
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 dark:text-slate-300">Palavra-passe</label>
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 group-focus-within:text-primary transition-colors">
                      <span className="material-symbols-outlined text-xl">lock</span>
                    </div>
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="w-full pl-10 pr-12 py-3.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all dark:text-white"
                      placeholder="••••••••"
                      required
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600 transition-colors"
                    >
                      <span className="material-symbols-outlined text-xl">
                        {showPassword ? 'visibility_off' : 'visibility'}
                      </span>
                    </button>
                  </div>
                </div>
                
                <div className="flex items-center justify-between">
                  <div className="flex items-center">
                    <input
                      className="h-4 w-4 text-primary focus:ring-primary border-slate-300 rounded cursor-pointer"
                      id="remember-me"
                      type="checkbox"
                    />
                    <label className="ml-2 block text-sm text-slate-600 dark:text-slate-400 cursor-pointer" htmlFor="remember-me">
                      Lembrar este dispositivo
                    </label>
                  </div>
                  <button type="button" onClick={() => setMode('forgot')} className="text-sm text-primary font-bold hover:underline">
                    Esqueceu a senha?
                  </button>
                </div>
                
                <button
                  type="submit"
                  className="w-full bg-primary hover:bg-primary/90 text-white font-bold py-4 rounded-lg shadow-lg shadow-primary/20 transition-all flex items-center justify-center gap-2"
                >
                  Entrar no Portal
                  <span className="material-symbols-outlined text-lg">arrow_forward</span>
                </button>

                <div className="mt-4 text-center">
                  <p className="text-slate-500 text-sm">
                    Ainda não possui conta?{' '}
                    <button type="button" onClick={() => setMode('register')} className="text-primary font-bold hover:underline">
                      Criar conta
                    </button>
                  </p>
                </div>
              </form>
            </>
          )}

          {mode === 'register' && (
            <>
              <div className="mb-6">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2">Criar Conta</h2>
                <p className="text-slate-500 dark:text-slate-400">Registe-se para aceder ao sistema</p>
                {errorString && (
                  <div className="mt-4 p-3 rounded-lg bg-red-100 text-red-700 text-sm font-semibold border border-red-200">
                    {errorString}
                  </div>
                )}
              </div>
              
              <form className="space-y-4" onSubmit={handleRegister}>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700 dark:text-slate-300">Nome Completo</label>
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 group-focus-within:text-primary transition-colors">
                      <span className="material-symbols-outlined text-xl">person</span>
                    </div>
                    <input
                      type="text"
                      value={name}
                      onChange={(e) => setName(e.target.value)}
                      className="w-full pl-10 pr-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all dark:text-white"
                      placeholder="Seu nome"
                      required
                    />
                  </div>
                </div>

                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700 dark:text-slate-300">Endereço de E-mail</label>
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 group-focus-within:text-primary transition-colors">
                      <span className="material-symbols-outlined text-xl">mail</span>
                    </div>
                    <input
                      type="email"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      className="w-full pl-10 pr-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all dark:text-white"
                      placeholder="seunome@empresa.ao"
                      required
                    />
                  </div>
                </div>
                
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700 dark:text-slate-300">Palavra-passe</label>
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 group-focus-within:text-primary transition-colors">
                      <span className="material-symbols-outlined text-xl">lock</span>
                    </div>
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="w-full pl-10 pr-12 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all dark:text-white"
                      placeholder="••••••••"
                      required
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600 transition-colors"
                    >
                      <span className="material-symbols-outlined text-xl">
                        {showPassword ? 'visibility_off' : 'visibility'}
                      </span>
                    </button>
                  </div>
                </div>

                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700 dark:text-slate-300">Confirmar Palavra-passe</label>
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 group-focus-within:text-primary transition-colors">
                      <span className="material-symbols-outlined text-xl">lock_reset</span>
                    </div>
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      className="w-full pl-10 pr-12 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all dark:text-white"
                      placeholder="••••••••"
                      required
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600 transition-colors"
                    >
                      <span className="material-symbols-outlined text-xl">
                        {showPassword ? 'visibility_off' : 'visibility'}
                      </span>
                    </button>
                  </div>
                </div>
                
                <button
                  type="submit"
                  className="w-full bg-primary hover:bg-primary/90 text-white font-bold py-3.5 mt-2 rounded-lg shadow-lg shadow-primary/20 transition-all flex items-center justify-center gap-2"
                >
                  Registar
                  <span className="material-symbols-outlined text-lg">app_registration</span>
                </button>

                <div className="mt-4 text-center">
                  <p className="text-slate-500 text-sm">
                    Já possui conta?{' '}
                    <button type="button" onClick={() => setMode('login')} className="text-primary font-bold hover:underline">
                      Inicie sessão
                    </button>
                  </p>
                </div>
              </form>
            </>
          )}

          {mode === 'confirm' && (
            <>
              <div className="mb-8">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2">Confirme a sua conta</h2>
                <p className="text-slate-500 dark:text-slate-400">Enviámos um código de confirmação para o seu email ({email})</p>
              </div>
              
              <form className="space-y-5" onSubmit={handleConfirm}>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 dark:text-slate-300">Código de Confirmação</label>
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 group-focus-within:text-primary transition-colors">
                      <span className="material-symbols-outlined text-xl">pin</span>
                    </div>
                    <input
                      type="text"
                      value={confirmCode}
                      onChange={(e) => setConfirmCode(e.target.value)}
                      className="w-full pl-10 pr-4 py-3.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all dark:text-white tracking-widest font-mono"
                      placeholder="000000"
                      required
                    />
                  </div>
                </div>
                
                <button
                  type="submit"
                  className="w-full bg-primary hover:bg-primary/90 text-white font-bold py-4 rounded-lg shadow-lg shadow-primary/20 transition-all flex items-center justify-center gap-2"
                >
                  Validar Código
                  <span className="material-symbols-outlined text-lg">verified</span>
                </button>

                <div className="mt-4 text-center">
                  <p className="text-slate-500 text-sm">
                    <button type="button" onClick={() => setMode('login')} className="text-primary font-bold hover:underline">
                      Voltar ao login
                    </button>
                  </p>
                </div>
              </form>
            </>
          )}

          {mode === 'forgot' && (
            <>
              <div className="mb-8">
                <button type="button" onClick={() => setMode('login')} className="flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-primary transition-colors mb-6 w-fit">
                  <span className="material-symbols-outlined text-lg">arrow_back</span>
                  Voltar
                </button>
                <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2">Esqueceu a sua senha?</h2>
                <p className="text-slate-500 dark:text-slate-400">Insira o seu email e enviaremos um link para redefinir a palavra-passe.</p>
              </div>
              
              <form className="space-y-5" onSubmit={handleForgotPassword}>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 dark:text-slate-300">Endereço de E-mail</label>
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 group-focus-within:text-primary transition-colors">
                      <span className="material-symbols-outlined text-xl">mail</span>
                    </div>
                    <input
                      type="email"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      className="w-full pl-10 pr-4 py-3.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all dark:text-white"
                      placeholder="seunome@empresa.ao"
                      required
                    />
                  </div>
                </div>
                
                <button
                  type="submit"
                  className="w-full bg-primary hover:bg-primary/90 text-white font-bold py-4 rounded-lg shadow-lg shadow-primary/20 transition-all flex items-center justify-center gap-2"
                >
                  Enviar Link de Recuperação
                  <span className="material-symbols-outlined text-lg">send</span>
                </button>
              </form>
            </>
          )}

          <div className="mt-auto pt-8 flex items-center justify-center gap-4 text-slate-400 text-xs">
            <span>© 2026 SALYA. Todos os direitos reservados.</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
